    order = make_order()
    process_order(order)  # covered but never asserted — meaningless

# Bad: all tests share one cart, order of execution matters
@pytest.fixture(scope="module")
def cart():
    c = ShoppingCart()
    c.add_item(price=100.0)
    return c

